// Message processor
async function processMessage(message, channel) {
  const messageId = message.properties.messageId || uuidv4();
  const startTime = Date.now();

  let parsedContent;

  try {
    const content = message.content.toString('utf-8');
    parsedContent = JSON.parse(content);
  } catch (parseError) {
    logger.error('Failed to parse message', { messageId, error: parseError.message });
    // Reject without requeue - send to dead letter queue
    channel.nack(message, false, false);
    return;
  }

  const { type, payload, correlationId } = parsedContent;

  try {
    // Validate message type
    const validatedType = validateMessageType(type);

    // Get handler
    const handler = messageHandlers[validatedType];
    if (!handler) {
      throw new Error(`No handler found for message type: ${validatedType}`);
    }

    if (!payload || typeof payload !== 'object') {
      throw new Error('Payload must be a non-null object');
    }

    // Execute handler
    const result = await handler(payload);
    const duration = Date.now() - startTime;

    logger.info('Message processed successfully', {
      messageId,
      correlationId,
      type: validatedType,
      duration: `${duration}ms`,
      result,
    });

    // Acknowledge the message
    channel.ack(message);
  } catch (error) {
    const duration = Date.now() - startTime;
    const retryCount = (message.properties.headers && message.properties.headers['x-retry-count']) || 0;
    const maxRetries = 3;

    logger.error('Failed to process message', {
      messageId,
      correlationId,
      type,
      error: error.message,
      duration: `${duration}ms`,
      retryCount,
    });

    if (retryCount < maxRetries) {
      // Requeue with retry count
      const headers = { ...message.properties.headers, 'x-retry-count': retryCount + 1 };
      channel.nack(message, false, false);

      // Republish with delay (using dead letter exchange with TTL for delayed retry)
      try {
        channel.publish('', config.rabbitmq.queue, message.content, {
          ...message.properties,
          headers,
          messageId,
        });
      } catch (republishError) {
        logger.error('Failed to republish message for retry', { messageId, error: republishError.message });
      }
    } else {
      // Max retries exceeded, send to dead letter queue
      logger.error('Max retries exceeded, sending to DLQ', { messageId, type });
      channel.nack(message, false, false);
    }
  }
}

// RabbitMQ connection management
class RabbitMQConsumer {
  constructor() {
    this.connection = null;
    this.channel = null;
    this.isConnecting = false;
    this.isShuttingDown = false;
  }

  async connect() {
    if (this.isConnecting || this.isShuttingDown) return;
    this.isConnecting = true;

    try {
      logger.info('Connecting to RabbitMQ...', { url: config.rabbitmq.url.replace(/\/\/.*@/, '//***@') });

      this.connection = await amqp.connect(config.rabbitmq.url);

      this.connection.on('error', (err) => {
        logger.error('RabbitMQ connection error', { error: err.message });
      });

      this.connection.on('close', () => {
        logger.warn('RabbitMQ connection closed');
        if (!this.isShuttingDown) {
          setTimeout(() => this.reconnect(), config.rabbitmq.reconnectDelay);
        }
      });

      this.channel = await this.connection.createChannel();

      this.channel.on('error', (err) => {
        logger.error('RabbitMQ channel error', { error: err.message });
      });

      this.channel.on('close', () => {
        logger.warn('RabbitMQ channel closed');
      });

      // Set prefetch
      await this.channel.prefetch(config.rabbitmq.prefetch);

      // Assert dead letter exchange and queue
      await this.channel.assertExchange('dlx_exchange', 'direct', { durable: true });
      await this.channel.assertQueue(config.rabbitmq.deadLetterQueue, {
        durable: true,
        arguments: {
          'x-message-ttl': 86400000, // 24 hours
        },
      });
      await this.channel.bindQueue(config.rabbitmq.deadLetterQueue, 'dlx_exchange', config.rabbitmq.queue);

      // Assert main queue with dead letter exchange
      await this.channel.assertQueue(config.rabbitmq.queue, {
        durable: true,
        arguments: {
          'x-dead-letter-exchange': 'dlx_exchange',
          'x-dead-letter-routing-key': config.rabbitmq.queue,
        },
      });

      logger.info('RabbitMQ connected and queue asserted', { queue: config.rabbitmq.queue });

      // Start consuming
      await this.channel.consume(config.rabbitmq.queue, async (message) => {
        if (message) {
          await processMessage(message, this.channel);
        }
      });

      logger.info('Consumer started, waiting for messages...', { queue: config.rabbitmq.queue });
      this.isConnecting = false;
    } catch (err) {
      this.isConnecting = false;
      logger.error('Failed to connect to RabbitMQ', { error: err.message });
      if (!this.isShuttingDown) {
        setTimeout(() => this.reconnect(), config.rabbitmq.reconnectDelay);
      }
    }
  }

  async reconnect() {
    logger.info('Attempting to reconnect to RabbitMQ...');
    await this.cleanup();
    await this.connect();
  }

  async cleanup() {
    try {
      if (this.channel) {
        await this.channel.close().catch(() => {});
        this.channel = null;
      }
      if (this.connection) {
        await this.connection.close().catch(() => {});
        this.connection = null;
      }
    } catch (err) {
      logger.error('Error during cleanup', { error: err.message });
    }
  }

  async shutdown() {
    logger.info('Shutting down consumer...');
    this.isShuttingDown = true;

    try {
      if (this.channel) {
        // Cancel consumer to stop receiving new messages
        await this.channel.cancel(config.rabbitmq.queue).catch(() => {});
      }
    } catch (err) {
      // Ignore cancel errors
    }

    await this.cleanup();
    await pool.end();
    logger.info('Consumer shut down gracefully');
  }
}

// Health check HTTP server
const http = require('http');

function createHealthServer(consumer) {
  const server = http.createServer(async (req, res) => {
    if (req.url === '/health' && req.method === 'GET') {
      try {
        const dbCheck = await pool.query('SELECT 1');
        const isHealthy = consumer.connection && consumer.channel && dbCheck.rowCount === 1;

        res.writeHead(isHealthy ? 200 : 503, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({
          status: isHealthy ? 'healthy' : 'unhealthy',
          rabbitmq: {
            connected: !!(consumer.connection && consumer.channel),
          },
          database: {
            connected: dbCheck.rowCount === 1,
            poolSize: pool.totalCount,
            idleConnections: pool.idleCount,
            waitingClients: pool.waitingCount,
          },
          timestamp: new Date().toISOString(),
        }));
      } catch (err) {
        res.writeHead(503, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({
          status: 'unhealthy',
          error: err.message,
          timestamp: new Date().toISOString(),
        }));
      }
    } else if (req.url === '/metrics' && req.method === 'GET') {
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({
        database: {
          totalConnections: pool.totalCount,
          idleConnections: pool.idleCount,
          waitingClients: pool.waitingCount,
        },
        uptime: process.uptime(),
        memoryUsage: process.memoryUsage(),
        timestamp: new Date().toISOString(),
      }));
    } else {
      res.writeHead(404, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Not found' }));
    }
  });

  const healthPort = process.env.HEALTH_PORT || 3000;
  server.listen(healthPort, () => {
    logger.info(`Health check server listening on port ${healthPort}`);
  });

  return server;
}

// Database initialization
async function initializeDatabase() {
  const client = await pool.connect();
  try {
    await client.query(`
      CREATE TABLE IF NOT EXISTS users (
        id UUID PRIMARY KEY,
        email VARCHAR(255) UNIQUE NOT NULL,
        name VARCHAR(100),
        metadata JSONB DEFAULT '{}',
        status VARCHAR(50) DEFAULT 'active',
        created_at TIMESTAMP WITH TIME ZONE NOT NULL,
        updated_at TIMESTAMP WITH TIME ZONE NOT NULL,
        deleted_at TIMESTAMP WITH TIME ZONE
      );

      CREATE TABLE IF NOT EXISTS orders (
        id UUID PRIMARY KEY,
        user_id UUID NOT NULL,
        total_amount DECIMAL(12, 2) NOT NULL,
        currency VARCHAR(3) DEFAULT 'USD',
        status VARCHAR(50) DEFAULT 'pending',
        cancellation_reason TEXT,
        metadata JSONB DEFAULT '{}',
        created_at TIMESTAMP WITH TIME ZONE NOT NULL,
        updated_at TIMESTAMP WITH TIME ZONE NOT NULL,
        completed_at TIMESTAMP WITH TIME ZONE
      );

      CREATE TABLE IF NOT EXISTS order_items (
        id UUID PRIMARY KEY,
        order_id UUID NOT NULL REFERENCES orders(id),
        product_id UUID NOT NULL,
        quantity INTEGER NOT NULL,
        unit_price DECIMAL(12, 2) NOT NULL,
        created_at TIMESTAMP WITH TIME ZONE NOT NULL
      );

      CREATE TABLE IF NOT EXISTS inventory (
        id UUID PRIMARY KEY,
        product_id UUID UNIQUE NOT NULL,
        quantity INTEGER DEFAULT 0,
        updated_at TIMESTAMP WITH TIME ZONE NOT NULL
      );

      CREATE TABLE IF NOT EXISTS notifications (
        id UUID PRIMARY KEY,
        user_id UUID NOT NULL,
        channel VARCHAR(50) NOT NULL,
        subject VARCHAR(200),
        body TEXT,
        metadata JSONB DEFAULT '{}',
        status VARCHAR(50) DEFAULT 'queued',
        created_at TIMESTAMP WITH TIME ZONE NOT NULL,
        sent_at TIMESTAMP WITH TIME ZONE
      );

      CREATE TABLE IF NOT EXISTS analytics_events (
        id UUID PRIMARY KEY,
        user_id UUID,
        event_name VARCHAR(100) NOT NULL,
        properties JSONB DEFAULT '{}',
        event_timestamp TIMESTAMP WITH TIME ZONE NOT NULL,
        created_at TIMESTAMP WITH TIME ZONE NOT NULL
      );

      CREATE TABLE IF NOT EXISTS audit_log (
        id UUID PRIMARY KEY,
        entity_type VARCHAR(50) NOT NULL,
        entity_id UUID NOT NULL,
        action VARCHAR(50) NOT NULL,
        details JSONB DEFAULT '{}',
        created_at TIMESTAMP WITH TIME ZONE NOT NULL
      );

      CREATE INDEX IF NOT EXISTS idx_orders_user_id ON orders(user_id);
      CREATE INDEX IF NOT EXISTS idx_orders_status ON orders(status);
      CREATE INDEX IF NOT EXISTS idx_order_items_order_id ON order_items(order_id);
      CREATE INDEX IF NOT EXISTS idx_inventory_product_id ON inventory(product_id);
      CREATE INDEX IF NOT EXISTS idx_notifications_user_id ON notifications(user_id);
      CREATE INDEX IF NOT EXISTS idx_analytics_events_user_id ON analytics_events(user_id);
      CREATE INDEX IF NOT EXISTS idx_analytics_events_event_name ON analytics_events(event_name);
      CREATE INDEX IF NOT EXISTS idx_audit_log_entity ON audit_log(entity_type, entity_id);
    `);

    logger.info('Database tables initialized successfully');
  } catch (err) {
    logger.error('Failed to initialize database tables', { error: err.message });
    throw err;
  } finally {
    client.release();
  }
}

// Main startup
async function main() {
  const consumer = new RabbitMQConsumer();

  // Graceful shutdown handlers
  const shutdown = async (signal) => {
    logger.info(`Received ${signal}, initiating graceful shutdown...`);
    await consumer.shutdown();
    process.exit(0);
  };

  process.on('SIGINT', () => shutdown('SIGINT'));
  process.on('SIGTERM', () => shutdown('SIGTERM'));

  process.on('uncaughtException', (err) => {
    logger.error('Uncaught exception', { error: err.message, stack: err.stack });
    shutdown('uncaughtException');
  });

  process.on('unhandledRejection', (reason) => {
    logger.error('Unhandled rejection', { reason: String(reason) });
  });

  try {
    // Initialize database tables
    await initializeDatabase();

    // Start health check server
    createHealthServer(consumer);

    // Connect to RabbitMQ and start consuming
    await consumer.connect();
  } catch (err) {
    logger.error('Failed to start service', { error: err.message });
    process.exit(1);
  }
}

main();

module.exports = {
  messageHandlers,
  validateMessageType,
  validateTableName,
  validateUUID,
  validateEmail,
  sanitizeString,
  processMessage,
};